-- calc_venues_name
-- Field: Venues.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_venues_name(p_venue_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(venue_id, '') FROM venues WHERE venue_id = p_venue_id))::text;
$$ LANGUAGE sql STABLE;

