-- calc_speakers_assignment_count
-- Field: Speakers.AssignmentCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_speakers_assignment_count(p_speaker_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM assignments WHERE speaker_ref = (SELECT NULLIF(speaker_id, '') FROM speakers WHERE speaker_id = p_speaker_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_speakers_is_overbooked
-- Field: Speakers.IsOverbooked
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_speakers_is_overbooked(p_speaker_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_speakers_assignment_count(p_speaker_id))::NUMERIC > 3)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_events_venue_capacity
-- Field: Events.VenueCapacity
-- Type: lookup | DataType: integer | Returns: INTEGER
-- Lookup: Capacity from related Venues


CREATE OR REPLACE FUNCTION calc_events_venue_capacity(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT capacity::integer FROM venues WHERE venue_id = (SELECT venue FROM events WHERE event_id = p_event_id));
