$$ LANGUAGE sql STABLE;

-- calc_events_booked_capacity
-- Field: Events.BookedCapacity
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_booked_capacity(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM rsvps WHERE event_ref = (SELECT NULLIF(event_id, '') FROM events WHERE event_id = p_event_id) AND status = 'confirmed'))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_available_capacity
-- Field: Events.AvailableCapacity
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_available_capacity(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE(CASE WHEN (calc_events_venue_capacity(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_venue_capacity(p_event_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_events_booked_capacity(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_booked_capacity(p_event_id))::numeric ELSE NULL END, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_at_capacity
-- Field: Events.AtCapacity
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_events_at_capacity(p_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_events_available_capacity(p_event_id))::NUMERIC <= 0)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_events_venue_conflict_count
-- Field: Events.VenueConflictCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_venue_conflict_count(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM events WHERE venue = (SELECT NULLIF(venue, '') FROM events WHERE event_id = p_event_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_has_venue_conflict
-- Field: Events.HasVenueConflict
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_events_has_venue_conflict(p_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_events_venue_conflict_count(p_event_id))::NUMERIC > 1)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_events_event_status
-- Field: Events.EventStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_events_event_status(p_event_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_events_has_speakers(p_event_id) AND NOT (calc_events_at_capacity(p_event_id)) AND NOT (calc_events_has_venue_conflict(p_event_id))) THEN ('ready')::text ELSE ('issues')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_events_registration_deadline
-- Field: Events.RegistrationDeadline
-- Type: calculated | DataType: datetime | Returns: TIMESTAMPTZ


CREATE OR REPLACE FUNCTION calc_events_registration_deadline(p_event_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT ((((SELECT event_date::timestamptz FROM events WHERE event_id = p_event_id))::date - (COALESCE(CASE WHEN ((SELECT registration_close_days_before_event FROM events WHERE event_id = p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT registration_close_days_before_event FROM events WHERE event_id = p_event_id))::numeric ELSE NULL END, 0))::integer))::timestamptz;
$$ LANGUAGE sql STABLE;

-- calc_events_is_registration_open
-- Field: Events.IsRegistrationOpen
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_events_is_registration_open(p_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_events_registration_deadline(p_event_id) > CURRENT_TIMESTAMP)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_events_capacity_headroom
-- Field: Events.CapacityHeadroom
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_events_capacity_headroom(p_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE(CASE WHEN (calc_events_available_capacity(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_available_capacity(p_event_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_events_booked_capacity(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_booked_capacity(p_event_id))::numeric ELSE NULL END, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_events_has_headroom_for_overbooking
-- Field: Events.HasHeadroomForOverbooking
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_events_has_headroom_for_overbooking(p_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_events_capacity_headroom(p_event_id) >= (COALESCE(CASE WHEN (calc_events_booked_capacity(p_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_events_booked_capacity(p_event_id))::numeric ELSE NULL END, 0) * COALESCE(0.2, 0)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_events_recommended_overbooking_factor
-- Field: Events.RecommendedOverbookingFactor
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_events_recommended_overbooking_factor(p_event_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_events_has_headroom_for_overbooking(p_event_id) THEN (1.2)::text ELSE (1.0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

